import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Test

class MultiLineIfElseRuleElseIfContinuationTest {
    private val multiLineIfElseRuleAssertThat = assertThatRule { MultiLineIfElseRule() }

    @Test
    fun `Issue - Given a multiline if-else-if with continuation operator - should not wrap else if in braces`() {
        val code =
            """
            fun test(showFilter: Boolean, activeTabIndex: Int): Int {
                val x = if (showFilter) {
                    1
                } else if (activeTabIndex == 0) {
                    2
                } else {
                    null
                } ?: 0
                return x
            }
            """.trimIndent()
        multiLineIfElseRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Issue - Given a multiline if-else-if with plus continuation - should not wrap else if in braces`() {
        val code =
            """
            fun test(bar1: Boolean, bar2: Boolean): String {
                val foo = if (bar1) {
                    "bar1"
                } else if (bar2) {
                    "bar2"
                } else {
                    "bar3"
                }.plus("foo")
                return foo
            }
            """.trimIndent()
        multiLineIfElseRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Issue - Given a multiline if-else-if-else with dot operator continuation - should not wrap else if in braces`() {
        val code =
            """
            fun test(a: Boolean, b: Boolean): String {
                return if (a) {
                    "a"
                } else if (b) {
                    "b"
                } else {
                    "c"
                }.uppercase()
            }
            """.trimIndent()
        multiLineIfElseRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Issue - Given multiple else-if branches with continuation - should not wrap any else if in braces`() {
        val code =
            """
            fun test(a: Boolean, b: Boolean, c: Boolean): Int {
                val result = if (a) {
                    1
                } else if (b) {
                    2
                } else if (c) {
                    3
                } else {
                    4
                } + 10
                return result
            }
            """.trimIndent()
        multiLineIfElseRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Issue - Given a nested else-if with continuation - should not wrap else if in braces`() {
        val code =
            """
            fun test(a: Boolean, b: Boolean, c: Boolean): String? {
                val result = if (a) {
                    if (b) {
                        "ab"
                    } else if (c) {
                        "ac"
                    } else {
                        "a"
                    }
                } else if (b) {
                    "b"
                } else {
                    null
                } ?: "default"
                return result
            }
            """.trimIndent()
        multiLineIfElseRuleAssertThat(code).hasNoLintViolations()
    }
}
